class Component extends DCLogic {
  constructor(props) {
    super(props);
    this.bannerRef = React.createRef();
    this.state = {
      term:   props.termValue   ?? '14',
      termUnit:    props.termUnit    ?? '天',
      rate:   props.rateValue   ?? '0.9',
      rateUnit:    props.rateUnit    ?? '%',
      amount: props.amountValue ?? '160+',
      amountUnit:  props.amountUnit  ?? 'USDT',
      scale: 2,
      batch: '',
      status: '',
      batchStatus: '',
      busy: false,
    };
  }

  setField(k) { return (e) => this.setState({ [k]: e.target.value }); }

  sanitize(s) {
    return String(s).replace(/[^\w\u4e00-\u9fa5.+%-]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 40) || 'x';
  }
  fileName(v) {
    return `USDT_${this.sanitize(v.term + v.termUnit)}_${this.sanitize(v.rate + v.rateUnit)}_${this.sanitize(v.amount + v.amountUnit)}.png`;
  }

  raf() { return new Promise(r => requestAnimationFrame(() => requestAnimationFrame(r))); }
  wait(ms) { return new Promise(r => setTimeout(r, ms)); }

  async capture(scale) {
    if (!window.htmlToImage) throw new Error('导出库未加载，请刷新');
    if (document.fonts && document.fonts.ready) { try { await document.fonts.ready; } catch (e) {} }
    const node = this.bannerRef.current;
    return await window.htmlToImage.toPng(node, {
      width: 960, height: 480,
      pixelRatio: scale || this.state.scale,
      cacheBust: true,
      backgroundColor: '#08111f',
    });
  }

  triggerDownload(href, name) {
    const a = document.createElement('a');
    a.href = href; a.download = name;
    document.body.appendChild(a); a.click(); a.remove();
  }

  downloadSingle = async () => {
    try {
      this.setState({ busy: true, status: '生成中…' });
      await this.raf();
      const url = await this.capture();
      this.triggerDownload(url, this.fileName(this.state));
      this.setState({ busy: false, status: '✓ 已下载' });
    } catch (err) {
      this.setState({ busy: false, status: '✕ ' + err.message });
    }
  };

  parseBatch() {
    return this.state.batch.split('\n').map(l => l.trim()).filter(Boolean).map(line => {
      const p = line.split(/[,，\t]+/).map(s => s.trim());
      return {
        term: p[0] ?? '', termUnit: (p[1] ?? '') || '天',
        rate: p[2] ?? '', rateUnit: (p[3] ?? '') || '%',
        amount: p[4] ?? '', amountUnit: (p[5] ?? '') || 'USDT',
      };
    });
  }

  downloadBatch = async () => {
    const rows = this.parseBatch();
    if (!rows.length) { this.setState({ batchStatus: '请先在上面输入数据' }); return; }
    if (!window.JSZip) { this.setState({ batchStatus: '打包库未加载，请刷新' }); return; }
    const saved = { term: this.state.term, termUnit: this.state.termUnit, rate: this.state.rate, rateUnit: this.state.rateUnit, amount: this.state.amount, amountUnit: this.state.amountUnit };
    try {
      this.setState({ busy: true, batchStatus: '准备中…' });
      const zip = new window.JSZip();
      const used = {};
      for (let i = 0; i < rows.length; i++) {
        const r = rows[i];
        this.setState({ term: r.term, termUnit: r.termUnit, rate: r.rate, rateUnit: r.rateUnit, amount: r.amount, amountUnit: r.amountUnit, batchStatus: `生成 ${i + 1}/${rows.length}…` });
        await this.raf(); await this.wait(50);
        const url = await this.capture();
        let name = this.fileName(r);
        if (used[name]) { name = name.replace(/\.png$/, '') + '_' + (used[name] + 1) + '.png'; used[this.fileName(r)]++; } else { used[this.fileName(r)] = 1; }
        zip.file(name, url.split(',')[1], { base64: true });
      }
      this.setState(saved);
      await this.raf();
      this.setState({ batchStatus: '打包中…' });
      const blob = await zip.generateAsync({ type: 'blob' });
      const u = URL.createObjectURL(blob);
      this.triggerDownload(u, `USDT_banners_${rows.length}.zip`);
      setTimeout(() => URL.revokeObjectURL(u), 8000);
      this.setState({ busy: false, batchStatus: `✓ 已打包 ${rows.length} 张` });
    } catch (err) {
      this.setState(saved);
      this.setState({ busy: false, batchStatus: '✕ ' + err.message });
    }
  };

  renderVals() {
    const s = this.state;
    return {
      termValue: s.term, termUnit: s.termUnit,
      rateValue: s.rate, rateUnit: s.rateUnit,
      amountValue: s.amount, amountUnit: s.amountUnit,
      bannerRef: this.bannerRef,

      term: s.term, su: s.termUnit,
      rate: s.rate, ru: s.rateUnit,
      amount: s.amount, au: s.amountUnit,
      onTerm: this.setField('term'), onTermUnit: this.setField('termUnit'),
      onRate: this.setField('rate'), onRateUnit: this.setField('rateUnit'),
      onAmount: this.setField('amount'), onAmountUnit: this.setField('amountUnit'),

      scale: s.scale,
      opt1: 1, opt2: 2, opt3: 3,
      onScale: (e) => this.setState({ scale: Number(e.target.value) }),
      busy: s.busy,
      status: s.status,

      batch: s.batch,
      onBatch: this.setField('batch'),
      batchPlaceholder: '14,天,0.9,%,160+,USDT\n7,天,0.5,%,100+,USDT\n30,天,1.8,%,500+,USDT',
      batchCount: this.parseBatch().length,
      batchStatus: s.batchStatus,
      downloadSingle: this.downloadSingle,
      downloadBatch: this.downloadBatch,
    };
  }
}

